    'nav.php' => base64_decode(''),
    'categories.js.php' => base64_decode(''),
    'api.php' => base64_decode(''),
    '.htaccess' => base64_decode('IyBCZXRhIGVudmlyb25tZW50CjxGaWxlc01hdGNoICJcLmNzcyQiPgogIEhlYWRlciBzZXQgQ2FjaGUtQ29udHJvbCAibm8tY2FjaGUsIG11c3QtcmV2YWxpZGF0ZSIKICBIZWFkZXIgc2V0IFByYWdtYSAibm8tY2FjaGUiCjwvRmlsZXNNYXRjaD4K'),
];

foreach ($files as $name => $content) {
